import boto3

def check_root_mfa(account_id, role_name="OrganizationAccountAccessRole"):
    """Check whether root MFA is enabled in a member account."""
    sts = boto3.client("sts")
    creds = sts.assume_role(
        RoleArn=f"arn:aws:iam::{account_id}:role/{role_name}",
        RoleSessionName="RootMFACheck"
    )["Credentials"]

    iam = boto3.client(
        "iam",
        aws_access_key_id=creds["AccessKeyId"],
        aws_secret_access_key=creds["SecretAccessKey"],
        aws_session_token=creds["SessionToken"],
    )

    summary = iam.get_account_summary()["SummaryMap"]
    return {
        "account_id": account_id,
        "root_mfa_enabled": bool(summary.get("AccountMFAEnabled", 0)),
        "root_access_keys": summary.get("AccountAccessKeysPresent", 0),
    }

def audit_organization_root_users():
    """Audit root user security across all organization accounts."""
    org = boto3.client("organizations")
    paginator = org.get_paginator("list_accounts")
    results = []

    for page in paginator.paginate():
        for account in page["Accounts"]:
            if account["Status"] != "ACTIVE":
                continue
            try:
                result = check_root_mfa(account["Id"])
                result["account_name"] = account["Name"]
                results.append(result)
            except Exception as e:
                results.append({
                    "account_id": account["Id"],
                    "account_name": account["Name"],
                    "error": str(e)
                })

    # Report accounts that need remediation
    non_compliant = [r for r in results if not r.get("root_mfa_enabled") or r.get("root_access_keys", 0) > 0]
    for account in non_compliant:
        print(f"NON-COMPLIANT: {account['account_name']} ({account['account_id']})")
        if not account.get("root_mfa_enabled"):
            print("  - Root MFA not enabled")
        if account.get("root_access_keys", 0) > 0:
            print("  - Root access keys present")

    return results
